    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Ortalamaya Dönüş, Görsel Anlatım — Bir Uç Değer Seçin, Bir Sonraki Değer Her Zaman Geri Döner</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Her iki grup da "aşırı düşük" bir değerle başlar, ama bir sonraki değer her zaman ortalamaya doğru hareket eder</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">Ortalama</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Gerçek bir göstergenin "dip" işaretlediği noktalar</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1tr)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI tek hane</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">Mar 2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1tr)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1tr)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Göstergesiz, rastgele seçilmiş uç değer</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2tr)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Rastgele dip 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2tr)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Rastgele dip 2</text>
    </g>
    <defs>
      <marker id="arrow1tr" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2tr" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A ve B aynı şekle sahiptir — uç bir değer seçmek zaten geri dönüşü programlar</text>
  </svg>
  </div>
  <div class="vi">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Hồi Quy Về Trung Bình, Minh Họa — Chọn Một Cực Trị, Giá Trị Tiếp Theo Luôn Quay Về</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Cả hai nhóm đều bắt đầu từ một giá trị "cực kỳ thấp", nhưng giá trị tiếp theo luôn di chuyển về phía mức trung bình</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">TB</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Các điểm mà một chỉ báo thực đánh dấu là "đáy"</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1vi)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI một chữ số</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">3/2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1vi)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1vi)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Cực trị ngẫu nhiên, chọn không cần chỉ báo</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2vi)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Đáy ngẫu nhiên 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2vi)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Đáy ngẫu nhiên 2</text>
    </g>
    <defs>
      <marker id="arrow1vi" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2vi" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A và B có cùng hình dạng — việc chọn một cực trị đã ngầm định sẵn sự hồi phục</text>
  </svg>
  </div>
  <div class="id">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Regresi ke Rata-Rata, Ilustrasi — Pilih Satu Nilai Ekstrem, Nilai Berikutnya Selalu Kembali</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Kedua kelompok mulai dari nilai yang "sangat rendah", tetapi nilai berikutnya selalu bergerak kembali ke rata-rata</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">Rata-rata</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Titik-titik yang ditandai indikator asli sebagai "dasar"</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1id)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI satu digit</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">Mar 2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1id)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1id)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Ekstrem acak, dipilih tanpa indikator</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2id)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Dasar acak 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2id)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Dasar acak 2</text>
    </g>
    <defs>
      <marker id="arrow1id" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2id" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A dan B terlihat sama — memilih nilai ekstrem sudah menjadwalkan pantulan</text>
  </svg>
  </div>
  <div class="pl">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Regresja do Średniej, Ilustracja — Wybierz Ekstremum, a Kolejna Wartość Zawsze Wraca</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Obie grupy zaczynają od "skrajnie niskiej" wartości, ale kolejna wartość zawsze przesuwa się z powrotem w stronę średniej</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">Średnia</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Punkty, które prawdziwy wskaźnik oznaczył jako "dołek"</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1pl)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI jednocyfrowe</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">Mar 2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1pl)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1pl)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Losowe ekstremum, wybrane bez wskaźnika</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2pl)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Losowy dołek 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2pl)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Losowy dołek 2</text>
    </g>
    <defs>
      <marker id="arrow1pl" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2pl" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A i B wyglądają tak samo — wybór ekstremum już z góry planuje odbicie</text>
  </svg>
  </div>
  <div class="it">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Regressione verso la Media, Illustrata — Seleziona un Estremo, il Valore Successivo Torna Sempre Indietro</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Entrambi i gruppi partono da un valore "estremamente basso", ma il valore successivo si muove sempre verso la media</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">Media</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Punti che un indicatore reale ha segnalato come "il minimo"</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1it)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI a una cifra</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">Mar 2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1it)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1it)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Estremo casuale, scelto senza indicatore</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2it)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Minimo casuale 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2it)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Minimo casuale 2</text>
    </g>
    <defs>
      <marker id="arrow1it" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2it" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A e B sembrano uguali — selezionare un estremo programma già il rimbalzo</text>
  </svg>
  </div>
  <div class="ru">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Регрессия к среднему, наглядно — выберите экстремум, и следующее значение всегда возвращается</text>
    <text x="20" y="52" fill="#a1a1aa" font-size="13" font-family="sans-serif">Обе группы начинаются со «крайне низкого» значения, но следующее значение всегда движется обратно к среднему</text>
    <line x1="40" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1" stroke-dasharray="5,5"/>
    <text x="665" y="334" fill="#71717a" font-size="13" font-family="sans-serif">Среднее</text>
    <text x="40" y="90" fill="#4ade80" font-size="14" font-weight="700" font-family="sans-serif">A. Точки, которые реальный индикатор пометил как «дно»</text>
    <g font-family="sans-serif">
      <circle cx="90" cy="230" r="6" fill="#f87171"/>
      <line x1="90" y1="224" x2="90" y2="140" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1ru)"/>
      <text x="90" y="255" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI однозначный</text>
      <text x="90" y="270" fill="#71717a" font-size="11" text-anchor="middle">март 2020</text>

      <circle cx="200" cy="245" r="6" fill="#f87171"/>
      <line x1="200" y1="239" x2="200" y2="150" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1ru)"/>
      <text x="200" y="270" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 20</text>

      <circle cx="310" cy="220" r="6" fill="#f87171"/>
      <line x1="310" y1="214" x2="310" y2="145" stroke="#4ade80" stroke-width="2.5" marker-end="url(#arrow1ru)"/>
      <text x="310" y="245" fill="#a1a1aa" font-size="12" text-anchor="middle">RSI &lt; 25</text>
    </g>
    <text x="410" y="90" fill="#60a5fa" font-size="14" font-weight="700" font-family="sans-serif">B. Случайный экстремум, выбранный без индикатора</text>
    <g font-family="sans-serif">
      <circle cx="460" cy="235" r="6" fill="#f87171"/>
      <line x1="460" y1="229" x2="460" y2="148" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2ru)"/>
      <text x="460" y="260" fill="#a1a1aa" font-size="12" text-anchor="middle">Случайный минимум 1</text>

      <circle cx="570" cy="225" r="6" fill="#f87171"/>
      <line x1="570" y1="219" x2="570" y2="142" stroke="#60a5fa" stroke-width="2.5" marker-end="url(#arrow2ru)"/>
      <text x="570" y="250" fill="#a1a1aa" font-size="12" text-anchor="middle">Случайный минимум 2</text>
    </g>
    <defs>
      <marker id="arrow1ru" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#4ade80"/></marker>
      <marker id="arrow2ru" markerWidth="8" markerHeight="8" refX="4" refY="4" orient="auto"><path d="M0,0 L8,4 L0,8 Z" fill="#60a5fa"/></marker>
    </defs>
    <text x="350" y="380" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">A и B выглядят одинаково — выбор экстремума уже предопределяет отскок</text>
